import React, { useState } from "react";

// Components
import SalesForm from "../../components/SalesForm";
import StockTable from "../../components/StockTable";
import Alerts from "../../components/Alerts";
import Analytics from "../../components/Analytics";
import InventoryPie from "../../components/InventoryPie";
import DashboardNavbar from "../../components/DashboardNavbar";

import "../../App.css";

/* 🔥 SALES SUGGESTIONS (Rule-based) */
const productSuggestions = {
  Milk: {
    pairWith: ["Bread", "Biscuit"],
    offer: "Buy Milk + Bread & get 5% off",
  },
  Maggi: {
    pairWith: ["Sauce", "Masala"],
    offer: "Buy 2 Maggi & get Sauce free",
  },
};

function Dashboard() {
  const [stock, setStock] = useState([
    {
      name: "Milk",
      quantity: 20,
      soldToday: 0,
      price: 30,
      cost: 25,
      expiry: "2026-01-10",
    },
    {
      name: "Maggi",
      quantity: 40,
      soldToday: 0,
      price: 15,
      cost: 10,
      expiry: "2026-03-01",
    },
  ]);

  const addSale = (itemName, soldQty) => {
    const updatedStock = stock.map((item) =>
      item.name === itemName
        ? {
            ...item,
            quantity: item.quantity - soldQty,
            soldToday: item.soldToday + soldQty,
          }
        : item
    );
    setStock(updatedStock);
  };

  return (
    <>
      <DashboardNavbar />

      <div className="container">
        {/* SALES FORM */}
        <div className="card">
          <SalesForm addSale={addSale} />
        </div>

        {/* STOCK TABLE */}
        <div className="card">
          <StockTable stock={stock} />
        </div>

        {/* ANALYTICS */}
        <div className="analytics-row">
          <div className="card chart-box">
            <Analytics stock={stock} />
          </div>

          <div className="card chart-box">
            <InventoryPie stock={stock} />
          </div>
        </div>

       {/* 🔥 SALES SUGGESTIONS CARD */}
<div className="card">
  <h3>💡 Sales Suggestions</h3>

  <div className="suggestion-list">
    {stock.map((item) =>
      productSuggestions[item.name] ? (
        <div className="suggestion-item" key={item.name}>
          <h4 className="suggestion-title">{item.name}</h4>

          <p className="suggestion-text">
            <span>Pair with:</span>{" "}
            {productSuggestions[item.name].pairWith.join(", ")}
          </p>

          <p className="suggestion-offer">
            🎯 {productSuggestions[item.name].offer}
          </p>
        </div>
      ) : null
    )}
  </div>
</div>


        {/* ALERTS */}
        <div className="card">
          <Alerts stock={stock} />
        </div>
      </div>
    </>
  );
}

export default Dashboard;
